export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/github_create_or_replace_file_1/result');
  const body = await response.json();

  const commitSha = body?.commit?.sha || '';
  const contentSha = body?.content?.sha || '';

  if (!commitSha && !contentSha) {
    throw new Error('GitHub connector result not finalized yet; retrying wait step.');
  }

  return { commitSha, contentSha, body };
}

export default async function ({ execution_id }) {
  const response = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/wait-for-github-operation/result');
  const payload = await response.json();

  const commitSha = payload?.commitSha || '';
  const contentSha = payload?.contentSha || '';

  if (!commitSha && !contentSha) {
    throw new Error('GitHub operation verification failed: missing commit/content SHA.');
  }

  return payload.body;
}
